}

let params = {
    face1: this.userface.replace("upload/", ""),
    face2: this.ruleForm.renlianshibie.replace("upload/", "")
}
const res = await this.$http.get("matchFace", { params: params });
if (res.data && res.data.code == 0 && res.data.score > 60) {
    this.faceMatchFlag = true;
    this.$message({ message: "匹配成功", type: "success" });
